+
+    @Test
+    void getTestCaseThrowsOnInvalidIndex() {
+        TestResults results = new TestResults(
+                List.of(new TestCase(List.of(new PyIntObj(1)))),
+                List.of(new HashSet<>()),
+                new HashSet<>());
+
+        assertThrows(IndexOutOfBoundsException.class, () -> results.getTestCase(-1));
+        assertThrows(IndexOutOfBoundsException.class, () -> results.getTestCase(1));
+    }
+
+    @Test
+    void computeExpectedResultsDoesNotModifySolutionFile() throws IOException, InterruptedException {
+        Path solutionFile = tempDir.resolve("solution.py");
+        Path implDir = tempDir.resolve("impl");
+        Files.createDirectories(implDir);
+        String original = "def identity(x):\n    return x\n";
+        Files.writeString(solutionFile, original);
+
+        Tester tester = new Tester(
+                "identity",
+                solutionFile.toString(),
+                implDir.toString(),
+                List.of(new TestCase(List.of(new PyIntObj(7)))));
+
+        assertEquals(List.of("7"), tester.computeExpectedResults());
+        assertEquals(original, Files.readString(solutionFile));
+    }
