+        Files.createDirectories(implDir);
+        Files.writeString(solutionFile, "def add(a, b):\n    return a + b\n");
+        Files.writeString(implDir.resolve("good.py"), "def add(a, b):\n    return a + b\n");
+        Files.writeString(implDir.resolve("bad.py"), "def add(a, b)\n    return a + b\n");
+        Files.writeString(implDir.resolve("notes.txt"), "not python");
+
+        List<TestCase> tests = Arrays.asList(
+                new TestCase(List.of(new PyIntObj(1), new PyIntObj(2))),
+                new TestCase(List.of(new PyIntObj(3), new PyIntObj(4))));
